import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PlayerData {
  player: {
    username: string;
    currentLevel: number;
    totalPlaytimeHours: number;
  };
  achievements: {
    name: string;
    unlocked: boolean;
  }[];
  levelProgress: {
    level: number;
    completion: number;
  }[];
}

export default function Widget() {
  const data = response.data as PlayerData;
  const { player, achievements, levelProgress } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="#F59E0B">
              {player.username}
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#F8FAFC' }}>
              Level {player.currentLevel}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Total Playtime: {player.totalPlaytimeHours} hours
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {achievements.slice(0, 3).map((achievement, index) => (
              <Chip
                key={index}
                label={achievement.name}
                sx={{
                  fontSize: '11px',
                  px: 1,
                  py: 0.5,
                  bgcolor: achievement.unlocked ? '#F59E0B' : '#374151',
                  color: '#F8FAFC',
                }}
              />
            ))}
          </Stack>

          <Box>
            <Typography variant="body2" color="#F59E0B" sx={{ mb: 0.5 }}>
              Level Progress
            </Typography>
            <BarChart
              height={100}
              series={[
                {
                  data: levelProgress.map(progress => progress.completion),
                  color: '#F59E0B',
                },
              ]}
              xAxis={[
                {
                  data: levelProgress.map(progress => `Lvl ${progress.level}`),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#F8FAFC',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
